type (
	FooRequest  = billing.GetFooInput
	FooResponse = api.BillingFoo
	FooParams   = string
	FooHandler  httptransport.HandlerWithArgs[FooRequest, FooResponse, FooParams]
)

func (h *handler) GetFoo() FooHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, customerID FooParams) (FooRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return FooRequest{}, err }
			return FooRequest{CustomerID: customer.CustomerID{Namespace: ns, ID: customerID}}, nil
		},
		func(ctx context.Context, req FooRequest) (FooResponse, error) {
			return h.billingService.GetFoo(ctx, req)
		},
		commonhttp.JSONResponseEncoderWithStatus[FooResponse](http.StatusOK),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("get-customer-foo"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
			httptransport.WithErrorEncoder(errorEncoder()),
		)...,
	)
}

